package com.example.easymoney.navigation
import androidx.compose.ui.graphics.Color
/** * Central route contracts and top-bar metadata for the app. */ sealed class AppDestination( val route: String, val title: String, val showBackButton: Boolean, val showHelpButton: Boolean = true, val guideXmlName: String? = null, val topBarBackgroundColor: Color? = null, val topBarContentColor: Color? = null ) { data object LoanInformation : AppDestination( route = "loan_information", title = "Thông tin khoản vay", showBackButton = false, topBarBackgroundColor = Color.White )
data object PageGuide : AppDestination( route = "page_guide?xml={xml}", title = "Hướng dẫn", showBackButton = true, showHelpButton = false, topBarBackgroundColor = Color.White ) { const val BASE_ROUTE = "page_guide" const val XML_ARG = "xml" const val DEFAULT_XML_NAME = "guide_default_updating"
fun createRoute(xmlName: String? = null): String { val normalized = xmlName?.trim().orEmpty() return if (normalized.isEmpty()) BASE_ROUTE else "$BASE_ROUTE?$XML_ARG=$normalized" } } }
fun appDestinationFromRoute(route: String?): AppDestination = when { route == AppDestination.LoanInformation.route -> AppDestination.LoanInformation route?.startsWith(AppDestination.PageGuide.BASE_ROUTE) == true -> AppDestination.PageGuide else -> AppDestination.LoanInformation }

package com.example.easymoney.navigation
import androidx.compose.ui.graphics.Color
/** * Central route contracts and top-bar metadata for the app. */ sealed class AppDestination( val route: String, val title: String, val showBackButton: Boolean, val showHelpButton: Boolean = true, val guideXmlName: String? = null, val topBarBackgroundColor: Color? = null, val topBarContentColor: Color? = null ) { data object Onboarding : AppDestination( route = "onboarding", title = "Vay tú chứcs tái chính", showBackButton = false, topBarBackgroundColor = Color.White )
data object LoanInformation : AppDestination( route = "loan_information", title = "Thông tin khoản vay", showBackButton = false, topBarBackgroundColor = Color.White )
data object PageGuide : AppDestination( route = "page_guide?xml={xml}", title = "Hướng dẫn", showBackButton = true, showHelpButton = false, topBarBackgroundColor = Color.White ) { const val BASE_ROUTE = "page_guide" const val XML_ARG = "xml" const val DEFAULT_XML_NAME = "guide_default_updating"
fun createRoute(xmlName: String? = null): String { val normalized = xmlName?.trim().orEmpty() return if (normalized.isEmpty()) BASE_ROUTE else "$BASE_ROUTE?$XML_ARG=$normalized" } } }
fun appDestinationFromRoute(route: String?): AppDestination = when { route == AppDestination.Onboarding.route -> AppDestination.Onboarding route == AppDestination.LoanInformation.route -> AppDestination.LoanInformation route?.startsWith(AppDestination.PageGuide.BASE_ROUTE) == true -> AppDestination.PageGuide else -> AppDestination.Onboarding }

package com.example.easymoney.navigation

import androidx.compose.runtime.Composable
import androidx.compose.ui.Modifier
import androidx.navigation.NavType
import androidx.navigation.NavHostController
import androidx.navigation.navArgument
import androidx.navigation.compose.NavHost
import androidx.navigation.compose.composable
import com.example.easymoney.data.model.LoanPackage
import com.example.easymoney.ui.guide.PageGuideScreen
import com.example.easymoney.ui.loan.LoanScreenMock

@Composable
fun AppNavHost(
    navController: NavHostController,
    modifier: Modifier = Modifier
) {
    NavHost(
        navController = navController,
        startDestination = AppDestination.LoanInformation.route,
        modifier = modifier
    ) {
        composable(AppDestination.LoanInformation.route) {
            val mockPackage = LoanPackage(
                id = "1",
                packageName = "Vay Nhanh",
                tenorRange = "6,12,18,24",
                minAmount = 6_000_000,
                maxAmount = 100_000_000,
                interest = 12.0,
                overdueCost = 5.0,
                eligibleCreditScore = 600
            )

            LoanScreenMock(
                mockPackage = mockPackage,
                initialAmount = 70_000_000,
                initialTenor = 6,
                initialInsuranceSelected = true
            )
        }

        composable(
            route = AppDestination.PageGuide.route,
            arguments = listOf(
                navArgument(AppDestination.PageGuide.XML_ARG) {
                    type = NavType.StringType
                    nullable = true
                    defaultValue = AppDestination.PageGuide.DEFAULT_XML_NAME
                }
            )
        ) { backStackEntry ->
            val xmlName = backStackEntry.arguments?.getString(AppDestination.PageGuide.XML_ARG)
            PageGuideScreen(xmlName = xmlName)
        }

        // Register new scene routes here as the product flow is expanded.
    }
}

package com.example.easymoney.navigation

import androidx.compose.runtime.Composable
import androidx.compose.ui.Modifier
import androidx.navigation.NavType
import androidx.navigation.NavHostController
import androidx.navigation.navArgument
import androidx.navigation.compose.NavHost
import androidx.navigation.compose.composable
import com.example.easymoney.data.model.LoanPackage
import com.example.easymoney.ui.guide.PageGuideScreen
import com.example.easymoney.ui.loan.LoanScreenMock
import com.example.easymoney.ui.onboarding.OnboardingScreen

@Composable
fun AppNavHost(
    navController: NavHostController,
    modifier: Modifier = Modifier
) {
    NavHost(
        navController = navController,
        startDestination = AppDestination.Onboarding.route,
        modifier = modifier
    ) {
        composable(AppDestination.Onboarding.route) {
            OnboardingScreen(
                onNavigateToLoan = {
                    navController.navigate(AppDestination.LoanInformation.route) {
                        popUpTo(AppDestination.Onboarding.route) { inclusive = true }
                    }
                }
            )
        }

        composable(AppDestination.LoanInformation.route) {
            val mockPackage = LoanPackage(
                id = "1",
                packageName = "Vay Nhanh",
                tenorRange = "6,12,18,24",
                minAmount = 6_000_000,
                maxAmount = 100_000_000,
                interest = 12.0,
                overdueCost = 5.0,
                eligibleCreditScore = 600
            )

            LoanScreenMock(
                mockPackage = mockPackage,
                initialAmount = 70_000_000,
                initialTenor = 6,
                initialInsuranceSelected = true
            )
        }

        composable(
            route = AppDestination.PageGuide.route,
            arguments = listOf(
                navArgument(AppDestination.PageGuide.XML_ARG) {
                    type = NavType.StringType
                    nullable = true
                    defaultValue = AppDestination.PageGuide.DEFAULT_XML_NAME
                }
            )
        ) { backStackEntry ->
            val xmlName = backStackEntry.arguments?.getString(AppDestination.PageGuide.XML_ARG)
            PageGuideScreen(xmlName = xmlName)
        }

        // Register new scene routes here as the product flow is expanded.
    }
}

